# MainViewController.swift
import UIKit
import GoogleMaps
import CoreLocation

class MainViewController: UIViewController {
    private var mapView: GMSMapView!
    private var locationManager: CLLocationManager!
    private var currentMarker: GMSMarker?
    private let infoView = UIView()
    private let titleLabel = UILabel()
    private let priceLabel = UILabel()
    private let bookButton = UIButton(type: .system)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Find & Book Locations"
        navigationController?.navigationBar.prefersLargeTitles = true
        
        setupLocationManager()
        setupMapView()
        setupInfoView()
        addSampleMarkers()
    }
    
    private func setupLocationManager() {
        locationManager = CLLocationManager()
        locationManager.delegate = self
        locationManager.requestWhenInUseAuthorization()
        locationManager.desiredAccuracy = kCLLocationAccuracyBest
        locationManager.startUpdatingLocation()
    }
    
    private func setupMapView() {
        let camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 12.0)
        mapView = GMSMapView.map(withFrame: view.bounds, camera: camera)
        mapView.isMyLocationEnabled = true
        mapView.settings.myLocationButton = true
        mapView.settings.compassButton = true
        mapView.delegate = self
        view.addSubview(mapView)
    }
    
    private func setupInfoView() {
        infoView.backgroundColor = .white
        infoView.layer.cornerRadius = 16
        infoView.layer.shadowColor = UIColor.black.cgColor
        infoView.layer.shadowOpacity = 0.1
        infoView.layer.shadowOffset = CGSize(width: 0, height: -2)
        infoView.layer.shadowRadius = 8
        infoView.translatesAutoresizingMaskIntoConstraints = false
        infoView.alpha = 0
        view.addSubview(infoView)
        
        titleLabel.font = UIFont.systemFont(ofSize: 20, weight: .semibold)
        titleLabel.translatesAutoresizingMaskIntoConstraints = false
        infoView.addSubview(titleLabel)
        
        priceLabel.font = UIFont.systemFont(ofSize: 24, weight: .bold)
        priceLabel.textColor = .systemGreen
        priceLabel.translatesAutoresizingMaskIntoConstraints = false
        infoView.addSubview(priceLabel)
        
        bookButton.setTitle("Book Now", for: .normal)
        bookButton.backgroundColor = .systemBlue
        bookButton.setTitleColor(.white, for: .normal)
        bookButton.layer.cornerRadius = 12
        bookButton.titleLabel?.font = UIFont.systemFont(ofSize: 18, weight: .semibold)
        bookButton.translatesAutoresizingMaskIntoConstraints = false
        bookButton.addTarget(self, action: #selector(bookButtonTapped), for: .touchUpInside)
        infoView.addSubview(bookButton)
        
        NSLayoutConstraint.activate([
            infoView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            infoView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            infoView.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -16),
            infoView.heightAnchor.constraint(equalToConstant: 180),
            
            titleLabel.topAnchor.constraint(equalTo: infoView.topAnchor, constant: 20),
            titleLabel.leadingAnchor.constraint(equalTo: infoView.leadingAnchor, constant: 20),
            titleLabel.trailingAnchor.constraint(equalTo: infoView.trailingAnchor, constant: -20),
            
            priceLabel.topAnchor.constraint(equalTo: titleLabel.bottomAnchor, constant: 8),
            priceLabel.leadingAnchor.constraint(equalTo: infoView.leadingAnchor, constant: 20),
            
            bookButton.leadingAnchor.constraint(equalTo: infoView.leadingAnchor, constant: 20),
            bookButton.trailingAnchor.constraint(equalTo: infoView.trailingAnchor, constant: -20),
            bookButton.bottomAnchor.constraint(equalTo: infoView.bottomAnchor, constant: -20),
            bookButton.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
    
    private func addSampleMarkers() {
        let locations = [
            ("Golden Gate Park", 37.7694, -122.4862, 45.00),
            ("Fisherman's Wharf", 37.8080, -122.4177, 60.00),
            ("Lombard Street", 37.8021, -122.4187, 35.00),
            ("Alcatraz Island", 37.8267, -122.4230, 85.00),
            ("Chinatown", 37.7941, -122.4078, 40.00)
        ]
        
        for location in locations {
            let marker = GMSMarker()
            marker.position = CLLocationCoordinate2D(latitude: location.1, longitude: location.2)
            marker.title = location.0
            marker.snippet = String(format: "$%.2f", location.3)
            marker.userData = location.3
            marker.map = mapView
        }
    }
    
    @objc private func bookButtonTapped() {
        guard let marker = currentMarker,
              let title = marker.title,
              let price = marker.userData as? Double else { return }
        
        let paymentVC = PaymentViewController(locationName: title, amount: price)
        navigationController?.pushViewController(paymentVC, animated: true)
    }
}

extension MainViewController: CLLocationManagerDelegate {
    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let location = locations.last else { return }
        let camera = GMSCameraPosition.camera(withLatitude: location.coordinate.latitude,
                                              longitude: location.coordinate.longitude,
                                              zoom: 14.0)
        mapView.animate(to: camera)
        locationManager.stopUpdatingLocation()
    }
}

extension MainViewController: GMSMapViewDelegate {
    func mapView(_ mapView: GMSMapView, didTap marker: GMSMarker) -> Bool {
        currentMarker = marker
        titleLabel.text = marker.title
        if let price = marker.userData as? Double {
            priceLabel.text = String(format: "$%.2f", price)
        }
        
        UIView.animate(withDuration: 0.3) {
            self.infoView.alpha = 1
        }
        
        return true
    }
    
    func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
        UIView.animate(withDuration: 0.3) {
            self.infoView.alpha = 0
        }
        currentMarker = nil
    }
}

# PaymentViewController.swift
import UIKit
import Stripe

class PaymentViewController: UIViewController {
    private let locationName: String
    private let amount: Double
    private let scrollView = UIScrollView()
    private let contentView = UIView()
    private let summaryView = UIView()
    private let locationLabel = UILabel()
    private let amountLabel = UILabel()
    private let paymentCardTextField = STPPaymentCardTextField()
    private let payButton = UIButton(type: .system)
    private let activityIndicator = UIActivityIndicatorView(style: .large)
    
    init(locationName: String, amount: Double) {
        self.locationName = locationName
        self.amount = amount
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Payment"
        view.backgroundColor = .systemGroupedBackground
        
        setupUI()
        setupKeyboardDismissal()
    }
    
    private func setupUI() {
        scrollView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(scrollView)
        
        contentView.translatesAutoresizingMaskIntoConstraints = false
        scrollView.addSubview(contentView)
        
        summaryView.backgroundColor = .white
        summaryView.layer.cornerRadius = 12
        summaryView.translatesAutoresizingMaskIntoConstraints = false
        contentView.addSubview(summaryView)
        
        let summaryTitle = UILabel()
        summaryTitle.text = "Booking Summary"
        summaryTitle.font = UIFont.systemFont(ofSize: 18, weight: .semibold)
        summaryTitle.translatesAutoresizingMaskIntoConstraints = false
        summaryView.addSubview(summaryTitle)
        
        locationLabel.text = locationName
        locationLabel.font = UIFont.systemFont(ofSize: 16)
        locationLabel.textColor = .secondaryLabel
        locationLabel.translatesAutoresizingMaskIntoConstraints = false
        summaryView.addSubview(locationLabel)
        
        amountLabel.text = String(format: "$%.2f", amount)
        amountLabel.font = UIFont.systemFont(ofSize: 28, weight: .bold)
        amountLabel.textColor = .systemGreen
        amountLabel.translatesAutoresizingMaskIntoConstraints = false
        summaryView.addSubview(amountLabel)
        
        let paymentTitle = UILabel()
        paymentTitle.text = "Payment Details"
        paymentTitle.font = UIFont.systemFont(ofSize: 18, weight: .semibold)
        paymentTitle.translatesAutoresizingMaskIntoConstraints = false
        contentView.addSubview(paymentTitle)
        
        paymentCardTextField.backgroundColor = .white
        paymentCardTextField.layer.cornerRadius = 12
        paymentCardTextField.borderWidth = 1
        paymentCardTextField.borderColor = .systemGray4
        paymentCardTextField.translatesAutoresizingMaskIntoConstraints = false
        contentView.addSubview(paymentCardTextField)
        
        payButton.setTitle("Pay Now", for: .normal)
        payButton.backgroundColor = .systemBlue
        payButton.setTitleColor(.white, for: .normal)
        payButton.layer.cornerRadius = 12
        payButton.titleLabel?.font = UIFont.systemFont(ofSize: 18, weight: .semibold)
        payButton.translatesAutoresizingMaskIntoConstraints = false
        payButton.addTarget(self, action: #selector(payButtonTapped), for: .touchUpInside)
        contentView.addSubview(payButton)
        
        activityIndicator.translatesAutoresizingMaskIntoConstraints = false
        activityIndicator.hidesWhenStopped = true
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            contentView.topAnchor.constraint(equalTo: scrollView.topAnchor),
            contentView.leadingAnchor.constraint(equalTo: scrollView.leadingAnchor),
            contentView.trailingAnchor.constraint(equalTo: scrollView.trailingAnchor),
            contentView.bottomAnchor.constraint(equalTo: scrollView.bottomAnchor),
            contentView.widthAnchor.constraint(equalTo: scrollView.widthAnchor),
            
            summaryView.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 20),
            summaryView.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            summaryView.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            summaryView.heightAnchor.constraint(equalToConstant: 140),
            
            summaryTitle.topAnchor.constraint(equalTo: summaryView.topAnchor, constant: 16),
            summaryTitle.leadingAnchor.constraint(equalTo: summaryView.leadingAnchor, constant: 16),
            
            locationLabel.topAnchor.constraint(equalTo: summaryTitle.bottomAnchor, constant: 12),
            locationLabel.leadingAnchor.constraint(equalTo: summaryView.leadingAnchor, constant: 16),
            
            amountLabel.topAnchor.constraint(equalTo: locationLabel.bottomAnchor, constant: 12),
            amountLabel.leadingAnchor.constraint(equalTo: summaryView.leadingAnchor, constant: 16),
            
            paymentTitle.topAnchor.constraint(equalTo: summaryView.bottomAnchor, constant: 30),
            paymentTitle.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            
            paymentCardTextField.topAnchor.constraint(equalTo: paymentTitle.bottomAnchor, constant: 16),
            paymentCardTextField.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            paymentCardTextField.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            paymentCardTextField.heightAnchor.constraint(equalToConstant: 60),
            
            payButton.topAnchor.constraint(equalTo: paymentCardTextField.bottomAnchor, constant: 30),
            payButton.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            payButton.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            payButton.heightAnchor.constraint(equalToConstant: 56),
            payButton.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -30),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }
    
    private func setupKeyboardDismissal() {
        let tapGesture = UITapGestureRecognizer(target: self, action: #selector(dismissKeyboard))
        view.addGestureRecognizer(tapGesture)
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
    
    @objc private func payButtonTapped() {
        guard paymentCardTextField.isValid else {
            showAlert(title: "Invalid Card", message: "Please enter valid card details")
            return
        }
        
        processPayment()
    }
    
    private func processPayment() {
        activityIndicator.startAnimating()
        payButton.isEnabled = false
        view.isUserInteractionEnabled = false
        
        guard let cardParams = paymentCardTextField.cardParams else {
            showPaymentError()
            return
        }
        
        let paymentMethodParams = STPPaymentMethodParams(card: cardParams, billingDetails: nil, metadata: nil)
        
        STPAPIClient.shared.createPaymentMethod(with: paymentMethodParams) { [weak self] paymentMethod, error in
            guard let self = self else { return }
            
            DispatchQueue.main.async {
                self.activityIndicator.stopAnimating()
                self.payButton.isEnabled = true
                self.view.isUserInteractionEnabled = true
                
                if let error = error {
                    self.showAlert(title: "Payment Error", message: error.localizedDescription)
                    return
                }
                
                guard let paymentMethod = paymentMethod else {
                    self.showPaymentError()
                    return
                }
                
                self.simulatePaymentIntent(with: paymentMethod.stripeId)
            }
        }
    }
    
    private func simulatePaymentIntent(with paymentMethodId: String) {
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) { [weak self] in
            guard let self = self else { return }
            self.showSuccessAlert()
        }
    }
    
    private func showPaymentError() {
        showAlert(title: "Payment Failed", message: "Unable to process payment. Please try again.")
    }
    
    private func showSuccessAlert() {
        let alert = UIAlertController(
            title: "Payment Successful!",
            message: "Your booking for \(locationName) has been confirmed.",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Done", style: .default) { [weak self] _ in
            self?.navigationController?.popToRootViewController(animated: true)
        })
        
        present(alert, animated: true)
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

